pub struct Terminal {
    pub grid: Grid,
    parser: vte::Parser,
}
impl Terminal {
    pub fn new(rows: u16, cols: u16, scrollback_max: usize) -> Self;
    pub fn process(&mut self, bytes: &[u8]) {
        let mut performer = Performer { grid: &mut self.grid, events: vec![] };
        for b in bytes { self.parser.advance(&mut performer, *b); }
    }
    pub fn drain_events(&mut self) -> Vec<TerminalEvent>; // OSC 7/title などを上位へ
}
struct Performer<'a> { grid: &'a mut Grid, events: Vec<TerminalEvent> }
impl vte::Perform for Performer<'_> { /* 各コールバック */ }
pub enum TerminalEvent { TitleChanged(String), CwdChanged(PathBuf), Bell }
```
